sendPacket(flags=SYN+ACK, seq=serverISN, ack=clientISN+1)
state = SYN_RECEIVED

// CLIENT SIDE (on receiving SYN-ACK)
sendPacket(flags=ACK, seq=clientISN+1, ack=serverISN+1)
state = ESTABLISHED

// SERVER SIDE (on receiving ACK)
state = ESTABLISHED

// Connection now established, both sides ready for data transfer

// CONGESTION CONTROL STATE VARIABLES
cwnd = 1 // congestion window in MSS
ssthresh = 65535 // slow start threshold
state = SLOW_START

// ON PACKET SENT
FUNCTION onPacketSent(seq):
 if state == SLOW_START:
 cwnd = cwnd + 1 // exponential growth per RTT
 if cwnd >= ssthresh:
 state = CONGESTION_AVOIDANCE

 else if state == CONGESTION_AVOIDANCE:
 // cwnd increases by 1/cwnd per ACK (approx 1 MSS per RTT)
 cwnd = cwnd + (1/cwnd)

// ON DUPLICATE ACK RECEIVED
FUNCTION onDuplicateACK(ackNum):
 dupCount++
 if dupCount == 3:
 // Fast Retransmit
 retransmit(ackNum)
 ssthresh = cwnd / 2
 cwnd = ssthresh + 3 // RFC 2581
 state = FAST_RECOVERY

// ON ACKNOWLEDGMENT RECEIVED (new ACK, not duplicate)
FUNCTION onNewACK(ackNum):
 if state == SLOW_START or state == CONGESTION_AVOIDANCE:
 cwnd = min(cwnd, ssthresh)
 state = CONGESTION_AVOIDANCE
 else if state == FAST_RECOVERY:
 cwnd = ssthresh
 state = CONGESTION_AVOIDANCE
 dupCount = 0

// ON TIMEOUT (most severe congestion)
FUNCTION onTimeout():
